  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';

  msg.state = Array.from(crypto.randomBytes(32))
    .map(b => chars[b % chars.length])
    .join('');
  return msg;
})();

