async function jwkThumbprintRFC7638(jwk) {
    // Seleziona solo i membri REQUIRED, in ordine lessicografico
    let canonical;
    if (jwk.kty === "EC") {
        canonical = {
            crv: jwk.crv,
            kty: jwk.kty,
            x: jwk.x,
            y: jwk.y,
        };
    } else if (jwk.kty === "RSA") {
        canonical = {
            e: jwk.e,
            kty: jwk.kty,
            n: jwk.n,
        };
    } else if (jwk.kty === "OKP") {
        canonical = {
            crv: jwk.crv,
            kty: jwk.kty,
            x: jwk.x,
        };
    } else {
        throw new Error(`Unsupported kty: ${jwk.kty}`);
    }
    const json = JSON.stringify(canonical); // niente spazi, ordine già imposto
    const hash = await sha256(Buffer.from(json, "utf8"));
    return base64url(hash);
}

