const { jwtVerify, decodeJwt, importJWK } = jose;

// --- CONFIG: identifier dell'Authorization Server / Credential Issuer (aud atteso) ---
// Per un issuer reale, impostalo da env/flow/global.
const ISSUER_ID = flow.get('issuer_id') || 'http://localhost:1880';

// --- store in-memory (GLOBAL) con TTL ---
function getStore() {
    return global.get('par_store') || {};
}
function setStore(s) {
    global.set('par_store', s);
}
function cleanupStore() {
    const store = getStore();
    const now = Date.now();
    let changed = false;
    for (const [k, v] of Object.entries(store)) {
        if (!v || v.expires_at_ms <= now) {
            delete store[k];
            changed = true;
        }
    }
    if (changed) setStore(store);
}

function base64url(buf) {
    return Buffer.from(buf)
        .toString('base64')
        .replace(/\+/g, '-')
        .replace(/\//g, '_')
        .replace(/=+$/g, '');
}

function jsonError(status, error, desc) {
    msg.statusCode = status;
    msg.headers = {
        ...(msg.headers || {}),
        'Content-Type': 'application/json',
        'Cache-Control': 'no-store'
    };
    msg.payload = {
        error,
        ...(desc ? { error_description: desc } : {})
    };
    return msg;
}

// --- MAIN ---
cleanupStore();

// Node-RED con x-www-form-urlencoded mette i campi in msg.payload come object
const body = msg.payload || {};
const client_id = new URLSearchParams(body).get("client_id");
const requestJwt = new URLSearchParams(body).get("request");

// RFC9126: request_uri NON deve essere presente nella PAR request
if (body.request_uri) {
    return jsonError(400, 'invalid_request', 'request_uri must not be provided to PAR endpoint');
}

if (!client_id || !requestJwt) {
    return jsonError(400, 'invalid_request', 'Missing client_id and/or request');
}

// Headers richiesti dal profilo IT-Wallet (PAR endpoint protetto)
const waa = msg.req?.headers?.['oauth-client-attestation'];
const waaPop = msg.req?.headers?.['oauth-client-attestation-pop'];
if (!waa || !waaPop) {
    return jsonError(401, 'invalid_client', 'Missing OAuth-Client-Attestation and/or OAuth-Client-Attestation-PoP');
}

(async () => {
    try {
        // 1) Estrai cnf.jwk dalla Wallet App Attestation (qui NON verifichiamo la trust chain: sandbox)
        let waaClaims = null;
        try {
            waaClaims = decodeJwt(waa);
        } catch (e) {
            // Errori JWT / audience / firma
            return jsonError(400, 'invalid_request', `waaClaims JWT validation failed: ${e.message}`);
        }
        const cnfJwk = waaClaims?.cnf?.jwk;
        if (!cnfJwk) {
            return jsonError(401, 'invalid_client', 'OAuth-Client-Attestation missing cnf.jwk');
        }

        // 2) Verifica la PoP JWT usando la cnf.jwk (dimostra possesso della chiave privata)
        //    NOTA: in produzione servono check completi (aud/iss/iat/jti finestra tempo, anti-replay, ecc.)
        let popResult = null;
        try {
            const publicKey = await jose.importJWK(cnfJwk, cnfJwk.alg || 'ES256');
            //public key estratta ma non utilizzata, valutare se passarla per ottenre il popresult
            popResult = await jwtVerify(waaPop, cnfJwk, {
                audience: ISSUER_ID
            });
        } catch (e) {
            // Errori JWT / audience / firma
            return jsonError(400, 'invalid_request', `popResult JWT validation failed: ${e.message}`);
        }
        const pop = popResult.payload;
        if (!pop.iss || pop.iss !== client_id) {
            return jsonError(401, 'invalid_client', 'Attestation PoP iss must match client_id');
        }
        if (!pop.iat || !pop.jti) {
            return jsonError(401, 'invalid_client', 'Attestation PoP missing iat/jti');
        }
        // 3) Verifica il Request Object (JAR) usando la stessa cnf.jwk
        let jarResult = null;
        try {
            jarResult = await jwtVerify(requestJwt, cnfJwk, {
                audience: ISSUER_ID
            });
        } catch (e) {
            // Errori JWT / audience / firma
            return jsonError(400, 'invalid_request', `jar JWT validation failed: ${e.message}`);
        }

        const ro = jarResult.payload;
        // Controlli minimi coerenti con JAR/PAR
        if (!ro.iss || ro.iss !== client_id) {
            return jsonError(400, 'invalid_request', !ro.iss ? 'Request Object iss is missing' : 'Request Object iss must equal client_id');
        }
        if (!ro.aud) {
            return jsonError(400, 'invalid_request', 'Request Object aud is missing');
        }

        if (ro.client_id && ro.client_id !== client_id) {
            return jsonError(400, 'invalid_request', 'Request Object client_id mismatch');
        }
        if (!ro.exp || (typeof ro.exp === 'number' && ro.exp <= Math.floor(Date.now() / 1000))) {
            return jsonError(400, 'invalid_request', 'Request Object expired or missing exp');
        }

        if (!ro.iat || (typeof ro.iat !== 'number')) {
            return jsonError(400, 'invalid_request', 'Request Object iat is not a number or missing');
        }
        if (ro.exp - ro.iat > 300) {
            return jsonError(400, 'invalid_request', 'exp claim too far from iat (max 300s)');
        }
        if (!ro.response_type || ro.response_type !== 'code') {
            return jsonError(400, 'invalid_request', 'response_type must be code');
        }
        if (!ro.redirect_uri) {
            return jsonError(400, 'invalid_request', 'Missing redirect_uri');
        }
        if (!ro.code_challenge) {
            return jsonError(400, 'invalid_request', 'Missing code_challenge');
        }

        if (ro.code_challenge_method != 'S256') {
            return jsonError(400, 'invalid_request', 'Code_challenge_method not valid');
        }

        if (!ro.scope) {
            return jsonError(400, 'invalid_request', 'Missing scope');
        }

        // regex: solo alfanumerico, minimo 32
        const alphanumeric32 = /^[A-Za-z0-9]{32,}$/;
        if (!alphanumeric32.test(ro.state)) {
            return jsonError(400, 'invalid_request', 'Value must be >=32 alphanumeric characters');
        }


        if (!ro.authorization_details || ro.authorization_details.length == 0 
        || ro.authorization_details.find(obj => obj.type !== "openid_credential" || !obj.credential_configuration_id)) {
             node.warn(ro)
            return jsonError(400, 'invalid_request', 'Authorization_details not valid');
        }
        const store = getStore();
        const entry = store[client_id] || {jti :[]}

        if (!ro.jti) {
            return jsonError(400, 'invalid_request', 'Missing jti');
        }
        //un jti può essere usato una sola volta a parità di client_id
        const exists = entry.jti.find(obj => obj === ro.jti);
        if (exists){
            return jsonError(400, 'invalid_request', 'JTI is already used');
        }
        //salvo il jti per storico
        entry.jti.push(ro.jti);
