/**
 * Handles the Nonce endpoint (POST /nonce).
 *
 * On success:
 * - Responds with HTTP 200 and JSON body: { "nonce": "<base64url>" }
 * - Sets Cache-Control: no-store
 *
 * On error:
 * - Responds with JSON error format: { error, error_description }
 * - Uses HTTP 500 for unexpected server errors
 * - Uses HTTP 503 when the endpoint is temporarily unavailable
 *
 * State:
 * - Persists issued nonces in a global in-memory store (global.nonce_store) with TTL.
 * - A separate periodic cleanup flow can prune expired entries; this node also prunes on each request.
 */

function jsonError(status, error, desc) {
  msg.statusCode = status;
  msg.headers = {
    ...(msg.headers || {}),
    'Content-Type': 'application/json',
    'Cache-Control': 'no-store'
  };
  msg.payload = {
    error,
    ...(desc ? { error_description: desc } : {})
  };
  return msg;
}

// The node expects Node.js 'crypto' to be provided through Function node external modules (see libs).
if (typeof crypto === 'undefined') {
  return jsonError(500, 'server_error', 'crypto module not available');
}

// Maintenance/overload switch.
// When flow.nonce_down is true, the endpoint must return 503 temporarily_unavailable.
const down = flow.get('nonce_down') || false;
if (down) {
  return jsonError(503, 'temporarily_unavailable', 'Service temporarily unavailable');
}

// Global in-memory store helpers.
function getStore() {
  return global.get('nonce_store') || {};
}
function setStore(store) {
  global.set('nonce_store', store);
}
function cleanupStore() {
  const store = getStore();
  const now = Date.now();
  let changed = false;

  // Removes expired entries to avoid unbounded memory growth.
  for (const [k, v] of Object.entries(store)) {
    if (!v || v.expires_at_ms <= now) {
      delete store[k];
      changed = true;
    }
  }

  if (changed) setStore(store);
}

// base64url helper (RFC 4648 URL-safe base64 without padding).
function base64url(buf) {
  return Buffer.from(buf)
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

try {
