  cleanupStore();

  // TTL policy in seconds (default: 60).
  // It can be overridden at runtime via flow.set('nonce_ttl_sec', <number>).
  let expires_in = Number(flow.get('nonce_ttl_sec') || 60);
  if (!Number.isFinite(expires_in) || expires_in <= 0) expires_in = 60;

  // Generates a cryptographically random nonce and encodes it as base64url.
  // 24 random bytes provide sufficient entropy for test environments.
  const c_nonce = base64url(crypto.randomBytes(24));

  // Stores nonce with absolute expiration timestamp.
  // The 'used' flag is reserved for one-time usage validation in future flows.
  const store = getStore();
  store[c_nonce] = {
    created_at_ms: Date.now(),
    expires_at_ms: Date.now() + (expires_in * 1000),
    used: false
  };
  setStore(store);

  // Success response.
  msg.statusCode = 200;
  msg.headers = {
    ...(msg.headers || {}),
    'Content-Type': 'application/json',
    'Cache-Control': 'no-store'
  };
  msg.payload = { c_nonce };
  return msg;

} catch (e) {
  // Generic internal error response (does not leak stack traces).
  return jsonError(500, 'server_error', 'The server encountered an unexpected error.');
}

