// Assert CI_028 - OAuth Client Attestation PoP Validation (Section 5.2)
// Collects split responses and evaluates:
//   28ko-* variants: expects 400 or 401 (invalid PoP rejected)
//   28ok: expects 201 (valid PoP accepted)

const fieldMap = {
    '28ko-iss': 'iss (issuer)',
    '28ko-aud': 'aud (audience)',
    '28ko-iat': 'iat (issued at)',
    '28ko-jti': 'jti (JWT ID)',
    '28ko-typ': 'typ (header type)',
    '28ko-key-changed': "Changed key"
    };

function evaluateEntry(entry, msg) {
    const subTestCase = entry.subTestCase;

    if (!subTestCase) {
        ci.addAssert(msg.test, 'PoP Validation', false, 'Error: missing subTestCase');
        return;
    }

 if (subTestCase === '28ko-key-changed') {
        const rejected = (entry.statusCode === 400 || entry.statusCode === 401);
        ci.addAssert(
            msg.test,
            'POP is not firmed with same key of attestation',
            rejected,
            rejected
                ? 'key mismatch rejected - HTTP ' + entry.statusCode
                : 'key mismatch not rejected - HTTP ' + entry.statusCode
        );
    } else
    if (subTestCase === '28ko-iss-sub') {
        const rejected = (entry.statusCode === 400 || entry.statusCode === 401);
        ci.addAssert(
            msg.test,
            'iss matches client attestation sub',
            rejected,
            rejected
                ? 'iss/sub mismatch rejected - HTTP ' + entry.statusCode
                : 'iss/sub mismatch not rejected - HTTP ' + entry.statusCode
        );
    } else if (subTestCase.startsWith('28ko')) {
        const fieldName = fieldMap[subTestCase] || subTestCase;
        const rejected = (entry.statusCode === 400 || entry.statusCode === 401);
        ci.addAssert(
            msg.test,
            'Missing ' + fieldName,
            rejected,
            rejected
                ? 'Missing ' + fieldName + ' rejected - HTTP ' + entry.statusCode
                : 'Missing ' + fieldName + ' not rejected - HTTP ' + entry.statusCode
        );
    } else if (subTestCase === '28ok') {
        const accepted = (entry.statusCode === 201);
        ci.addAssert(
            msg.test,
            'Complete PoP JWT',
            accepted,
            accepted
                ? 'Valid PoP accepted - HTTP ' + entry.statusCode
                : 'Valid PoP not accepted - HTTP ' + entry.statusCode
        );
    }
}

