    );
    cleanup(id);
    return fail("count-mismatch");
}

const [first, second] = sessions[id].buffer;

// =====================================================
// Classificazione errori 400
// =====================================================
const CLASSIFIERS = [
    ["expired request_uri", "expired"],
    ["request_uri already used (too many duplicates)", "tooMany"],
    ["request_uri already used", "alreadyUsed"],
    ["unknown request_uri", "unknownUri"],
    ["missing request_uri", "missingUri"],
    ["client_id does not match par", "clientMismatch"]
];

const LABELS = {
    expired: "400 - Expired request_uri",
    tooMany: "400 - Too many duplicates",
    alreadyUsed: "400 - Already used (outside reload/refresh window / non-compliant)",
    unknownUri: "400 - Unknown request_uri (no matching PAR)",
    missingUri: "400 - Missing request_uri (PAR required)",
    clientMismatch: "400 - client_id does not match PAR",
    other: "400 - Unexpected error"
};

function classify(desc = "") {
    const s = desc.toLowerCase();
    for (const [needle, label] of CLASSIFIERS) {
        if (s.includes(needle)) return label;
    }
    return "other";
}

// =====================================================
// Asserzioni
// =====================================================
let ok = false;
let finalNote = "";

// 0) Baseline: prima risposta deve essere 302
const baselineOk = first.statusCode === 302;
ci.addAssert(
    msg.test,
    "Baseline: first response /authorize is 302",
    baselineOk,
    `s1=${first.statusCode}${baselineOk ? "" : first.errDesc ? ` (${first.errDesc})` : ""}`
);

if (!baselineOk) {
    if (first.statusCode === 400) {
        const cat = classify(first.errDesc);
        ci.addAssert(
            msg.test,
            LABELS[cat],
            false,
            first.errDesc || "Unspecified error"
        );
    }
    finalNote = "Baseline failed: First response is not 302";
    ok = false;
} else {
    switch (second.statusCode) {
        case 302: {
            const sameLocation =
                !!first.location && first.location === second.location;
            ci.addAssert(
                msg.test,
                "User reloading or refreshing their user-agent",
                sameLocation,
                sameLocation
                    ? `Same location:\nL1=${first.location}\nL2=${second.location}`
                    : `Different location:\nL1=${first.location}\nL2=${second.location}`
            );
            ok = sameLocation;
            finalNote = sameLocation
                ? "302/302 : Same location"
                : "Different location, it's not a user reloading/refreshing";
            break;
        }
        case 400: {
            const cat = classify(second.errDesc);
            ci.addAssert(
                msg.test,
                LABELS[cat],
                false,
                second.errDesc || "Unspecified error"
            );
            ok = false;
            finalNote = "Second response is 400";
            break;
        }
        default:
            ci.addAssert(
                msg.test,
                "Unexpected status in the second response",
                false,
                `s2=${second.statusCode} — Make sure followRedirects=false`
            );
            ok = false;
            finalNote = "Second response is neither 302 nor 400";
    }
}

// =====================================================
