function evaluateEntry(entry, msg) {
    const t = entry.subTestCase;
    if (!t) { ci.addAssert(msg.test, 'Token Response', false, 'Error: missing subTestCase'); return; }
    const exp = expectations[t];
    if (!exp) return;
    const body = (function() { try { return JSON.parse(entry.payload); } catch(e) { return {}; } })();
    const passed = entry.statusCode === exp.code && (!exp.error || body.error === exp.error);
    const got = 'HTTP ' + entry.statusCode + (body.error ? ', error: ' + body.error : '');
    const want = 'HTTP ' + exp.code + (exp.error ? ' with error=' + exp.error : '');
    ci.addAssert(msg.test, t, passed, passed ? 'OK - ' + got : 'Expected ' + want + ' - Got: ' + got);
}

