    '87ok':                          { code: 204 },
    '87ko-invalid_notification_id':  { code: 400, error: 'invalid_notification_id' },
    '87ko-missing_notification_id':  { code: 400, error: 'invalid_notification_request' },
    '87ko-invalid_event':            { code: 400, error: 'invalid_notification_request' },
    '87ko-missing_event':            { code: 400, error: 'invalid_notification_request' },
    '87ko-missing_auth':             { code: 401 }
