/**
 * Evaluates a single buffered entry against the expected outcome.
 * Adds an assertion to the test report for each entry.
 */
function evaluateEntry(entry, msg) {
    const t = entry.subTestCase;
    if (!t) {
        ci.addAssert(msg.test, 'Notification Response', false, 'Error: missing subTestCase');
        return;
    }

    const exp = expectations[t];
    if (!exp) return;

    // Parse the response body (may be empty for 204 or a JSON error object)
    const body = (function () {
        if (!entry.payload || entry.payload === '') return {};
        try { return JSON.parse(entry.payload); } catch (e) { return {}; }
    })();

    // Determine if the response matches the expected outcome
    const statusMatch = (entry.statusCode === exp.code);
    const errorMatch  = (!exp.error || body.error === exp.error);
    const passed      = statusMatch && errorMatch;

    // Build human-readable strings for the assertion details
    const got  = 'HTTP ' + entry.statusCode + (body.error ? ', error: ' + body.error : '');
    const want = 'HTTP ' + exp.code + (exp.error ? ' with error=' + exp.error : '');

    ci.addAssert(
        msg.test,
        t,
        passed,
        passed ? 'OK - ' + got : 'Expected ' + want + ' - Got: ' + got
    );
}

