/**
 * CI_120 – Signature of SD-JWT credential
 *
 * Verifies that the credential in SD-JWT format is signed with the Issuer's private key.
 * Checks: alg header present, signature component non-empty, typ header identifies credential type.
 * If the Issuer JWKS is available on msg.ci_metadata.jwks, full cryptographic verification is attempted.
 */
const ci = global.get('ciCommon');
const jose = global.get('jose');

// Helper: parse SD-JWT Combined Format into { jwt, header, payload, disclosures }
function parseSDJWT(raw) {
    const parts = raw.split('~');
    const jwt = parts[0];
    const jp = jwt.split('.');
    if (jp.length !== 3) throw new Error('Invalid JWT structure: expected 3 dot-separated parts');
    return {
        jwt: jwt,
        header: JSON.parse(Buffer.from(jp[0], 'base64url').toString()),
        payload: JSON.parse(Buffer.from(jp[1], 'base64url').toString()),
        disclosures: parts.slice(1).filter(function(d) { return d.length > 0; })
    };
}

// Session management: collect all split messages before evaluating
const contextKey = 'sessionsCi_120';
let sessions = context.get(contextKey) || {};
const id = msg.innerSplit._id;

if (!msg.innerSplit || !msg.innerSplit.total || msg.innerSplit.total < 1) {
    delete msg.subTestCase;
    return msg;
}

if (!sessions[id]) sessions[id] = { buffer: [], startTime: Date.now() };
context.set(contextKey, sessions);
sessions[id].buffer.push({ statusCode: msg.statusCode, payload: msg.payload, subTestCase: msg.subTestCase });
if (msg.innerSplit.total !== sessions[id].buffer.length) return null;

// Evaluate all buffered entries
for (const entry of sessions[id].buffer) {
    const body = typeof entry.payload === 'string'
        ? (function() { try { return JSON.parse(entry.payload); } catch(e) { return {}; } })()
        : (entry.payload || {});
    const credential = body.credential;

    if (!credential) {
        ci.addAssert(msg.test, 'SD-JWT credential present in response', false,
            'No "credential" field found in Credential Endpoint response (statusCode=' + entry.statusCode + ')');
        continue;
    }

    let parsed;
    try { parsed = parseSDJWT(credential); }
    catch(e) { ci.addAssert(msg.test, 'SD-JWT credential parseable', false, 'Parse error: ' + e.message); continue; }

    // Check the alg header declares a signing algorithm
    ci.addAssert(msg.test, 'SD-JWT alg header declares signing algorithm', !!parsed.header.alg,
        parsed.header.alg ? 'alg=' + parsed.header.alg : 'alg header MISSING');

    // Check the signature component (3rd JWT part) is present and non-empty
    const sigPart = parsed.jwt.split('.')[2];
    ci.addAssert(msg.test, 'SD-JWT signature component present and non-empty',
        !!(sigPart && sigPart.length > 10),
        sigPart ? 'Signature: ' + sigPart.substring(0, 20) + '... (' + sigPart.length + ' chars)' : 'Signature EMPTY or missing');

    // Check typ header identifies the credential type
    ci.addAssert(msg.test, 'SD-JWT typ header present', !!parsed.header.typ,
        parsed.header.typ ? 'typ=' + parsed.header.typ : 'typ header MISSING');

    // Attempt full cryptographic verification using Issuer JWKS if available
    const issuerJwks = (msg.ci_metadata && msg.ci_metadata.jwks) || (msg.oauth_as_metadata && msg.oauth_as_metadata.jwks);
    if (issuerJwks && issuerJwks.keys && issuerJwks.keys.length > 0) {
        try {
            const JWKS = jose.createLocalJWKSet(issuerJwks);
            await jose.jwtVerify(parsed.jwt, JWKS);
            ci.addAssert(msg.test, 'SD-JWT signature cryptographically valid against Issuer JWKS', true,
                'Signature verified successfully using Issuer JWKS; alg=' + parsed.header.alg);
        } catch(e) {
            ci.addAssert(msg.test, 'SD-JWT signature cryptographically valid against Issuer JWKS', false,
                'Verification failed: ' + e.message);
        }
    }
}

msg.test.suite = 'CI_120_SUITE';
msg.test.name = 'Data Model and lifecycle, Security – Signature of the SD-JWT credential';
ci.buildResponse(msg);
context.set(contextKey, null);
delete msg.subTestCase;
return msg;

