// @ts-ignore
const crypto = global.get("crypto");
const { SignJWT } = jose;
const privateKey = msg.session.key.privateKey;
const publicKey = msg.session.key.publicKey;

const pubJwk = publicKey.export({ format: 'jwk' });
pubJwk.kid = pubJwk.kid || 'mock-key-1';
pubJwk.alg = pubJwk.alg || msg.attestationPars.alg;

const clientId = msg.attestationPars.iss;
const issuerId = msg.attestationPars.issuer_id;
const alg = msg.attestationPars.alg;

function buildNewKey(_alg){
    let { publicKey, privateKey } = crypto.generateKeyPairSync("ec", {
        namedCurve: "prime256v1"
    });
    const pubJwk = publicKey.export({ format: 'jwk' });
    pubJwk.kid = pubJwk.kid || 'mock-key-1';
    pubJwk.alg = pubJwk.alg ||_alg;
    return { privateKey, publicKey, pubJwk}
}

// Build and sign a PoP JWT, optionally omitting one required field
async function signPopVariant(_variant) {
    const payload = {
        htm: 'POST',
        htu: '/par'
    };

    if (_variant.omitField !== 'jti') {
        payload.jti = crypto.randomBytes(12).toString('hex');
    }

    const header = { alg: _variant.keys.pubJwk.alg, kid: _variant.keys.pubJwk.kid };
    if (_variant.omitField !== 'typ') {
        header.typ = 'oauth-client-attestation-pop+jwt';
    }

    const builder = new SignJWT(payload)
        .setProtectedHeader(header);

    if (_variant.omitField !== 'iss') builder.setIssuer(_variant.issOverride || clientId);
    if (_variant.omitField !== 'aud') builder.setAudience(issuerId);
    if (_variant.omitField !== 'iat') builder.setIssuedAt();

    return builder.sign(_variant.keys.privateKey);
}


