/**
 * CI_087 - Notification Response Table of HTTP Status Codes
 *
 * Generates multiple notification request variants to verify that
 * the Credential Issuer returns the correct HTTP status code and
 * error code for each scenario defined in the specification.
 *
 * VARIANT STRATEGY (following the same pattern as Set CI_067):
 *
 *   87ok                         → Valid request with all required fields
 *   87ko-invalid_notification_id → Uses a fabricated notification_id
 *   87ko-missing_notification_id → Omits the notification_id entirely
 *   87ko-invalid_event           → Uses an unsupported event value
 *   87ko-missing_event           → Omits the event field entirely
 *   87ko-missing_auth            → Removes Authorization + DPoP headers
 *
 * Each variant is emitted as a separate msg with innerSplit metadata
 * so the Assert CI_087 node can buffer and evaluate them as a batch.
 */

const splittedId = Math.random();

/**
 * Builds a JSON notification body, optionally omitting or replacing fields.
 * @param {string|null} notificationId - The notification_id value (null to omit)
 * @param {string|null} event          - The event value (null to omit)
 * @returns {string} Serialised JSON body
 */
function buildBody(notificationId, event) {
    const body = {};
    if (notificationId !== null) body.notification_id = notificationId;
    if (event !== null) body.event = event;
    return JSON.stringify(body);
}

/**
 * Applies header modifications: sets to value or deletes if null.
 */
function applyHeaderMods(headers, mods) {
    Object.keys(mods).forEach(function (k) {
        if (mods[k] === null) {
            delete headers[k];
        } else {
            headers[k] = mods[k];
        }
    });
}

// Retrieve the notification_id received from the Credential Response (Step 20-24)
