const validEvent = 'credential_accepted';

// Define all test case variants
const cases = [
    {
        sub: '87ok',
        body: buildBody(validNotificationId, validEvent),
        headerMods: {}
    },
    {
        sub: '87ko-invalid_notification_id',
        body: buildBody('non-existent-notification-id-12345', validEvent),
        headerMods: {}
    },
    {
        sub: '87ko-missing_notification_id',
        body: buildBody(null, validEvent),
        headerMods: {}
    },
    {
        sub: '87ko-invalid_event',
        body: buildBody(validNotificationId, 'invalid_event_value'),
        headerMods: {}
    },
    {
        sub: '87ko-missing_event',
        body: buildBody(validNotificationId, null),
        headerMods: {}
    },
    {
        sub: '87ko-missing_auth',
        body: buildBody(validNotificationId, validEvent),
        headerMods: { 'Authorization': null, 'DPoP': null }
    }
];

// Emit one message per variant, each tagged with innerSplit for buffered evaluation
cases.forEach(function (c, i) {
    const m = RED.util.cloneMessage(msg);

    // Override the payload with the variant-specific JSON body
    m.payload = c.body;

    // Ensure Content-Type is set for all variants
    m.headers = m.headers || {};
    m.headers['Content-Type'] = 'application/json';

    // Apply header modifications (e.g. remove Authorization for 87ko-missing_auth)
    if (c.headerMods && Object.keys(c.headerMods).length > 0) {
        applyHeaderMods(m.headers, c.headerMods);
    }

    // Tag the message with split metadata for the Assert node
    m.innerSplit = { index: i, _id: splittedId, total: cases.length };
    m.subTestCase = c.sub;

    node.send(m);
});

