    sessions[id].buffer.forEach(function (element) {
        const value = element.testId;
        successed = element.payload.ok ? ++successed : successed;
        totalTest+=1;
        msg.tested.push(
            { "testID": value , 
             "global outcome": element.payload.ok ,
             "name":  "",
             "sub outcome": "" ,
                "details": element.payload.test.name }
        );
