        for (let i = 0; i < asserts.length; i++){

                    msg.tested.push(
            { "testID": value ,
            "global outcome": "" ,
                            "name": asserts[i].name,
                            "sub outcome": asserts[i].ok ,
                            "details": asserts[i].details }
        );
        }


    });

    msg.payload = {
        outcomes: msg.tested,
        endEndWithSuccess: successed,
        totalTest:totalTest
    }

    delete msg.splittedInfo;
    delete msg.testId;
    delete sessions[id];
    return msg;
}

