function generateEcP256Pair() {
    const { privateKey, publicKey } = crypto.generateKeyPairSync('ec', {
        namedCurve: 'P-256',
        publicKeyEncoding: { type: 'spki', format: 'pem' },    // SPKI for public
        privateKeyEncoding: { type: 'pkcs8', format: 'pem' }   // PKCS8 for private
    });
    return { privPem: privateKey, pubPem: publicKey };
}

